// Consultant-focused contract templates. Ported from ctaxwave.
// Curated subset of 11 templates that a small-business consultant
// actually uses: getting work, NDAs, protections, hiring 1099s.
//
// Each template is a fill-in-the-blank document with {{mustache}}
// placeholders that get replaced by field_values when rendered.

export type FieldType =
  | "text"
  | "number"
  | "date"
  | "textarea"
  | "signature"
  | "dropdown"
  | "checkbox"
  | "radio"
  | "email";

export interface ContractField {
  id: string;
  key: string;
  label: string;
  type: FieldType;
  value: string;
  placeholder: string;
  section: string;
  required?: boolean;
  options?: readonly string[];
}

export interface ContractSection {
  id: string;
  title: string;
  content: string;
  order: number;
}

export interface ContractTemplate {
  id: string;
  name: string;
  description: string;
  icon: string;
  category: "engagement" | "protection" | "hiring";
  sections: ContractSection[];
  fields: ContractField[];
}

const TEMPLATE_CATEGORY: Record<string, "engagement" | "protection" | "hiring"> = {
  "consulting-agreement": "engagement",
  "master-services-agreement": "engagement",
  "statement-of-work": "engagement",
  "retainer-agreement": "engagement",
  "mutual-nda": "protection",
  "one-way-nda": "protection",
  "ip-assignment": "protection",
  "employee-confidentiality": "protection",
  "independent-contractor": "hiring",
  "freelance-services": "hiring",
  "subcontractor-agreement": "hiring",
};

