export const CONTRACT_TEMPLATES: ContractTemplate[] = TEMPLATES_RAW.map((t) => ({
  ...t,
  category: TEMPLATE_CATEGORY[t.id] || "engagement",
}));

export function getTemplate(id: string): ContractTemplate | undefined {
  return CONTRACT_TEMPLATES.find((t) => t.id === id);
}

// Fill mustache placeholders ({{key}}) in a section's content using a values map.
export function renderSectionContent(content: string, values: Record<string, string | undefined>): string {
  return content.replace(/\{\{\s*(\w+)\s*\}\}/g, (_, key) => values[key] ?? `{{${key}}}`);
}
